// Inline: wf-monitor-logic (buildMonitoringReport) with deduplication
const SCHEDULE_GAP_THRESHOLD_H = 25;
const BACKUP_STALE_THRESHOLD_H = 26;
const DISK_THRESHOLD_GB = 20;

function hoursBetween(olderIso, nowIso) {
  if (!olderIso) return Number.POSITIVE_INFINITY;
  const start = new Date(olderIso).getTime();
  const end = new Date(nowIso).getTime();
  if (!Number.isFinite(start)) return Number.POSITIVE_INFINITY;
  return (end - start) / 36e5;
}

function isoDay(isoString) {
  return String(isoString || new Date().toISOString()).slice(0, 10);
}

function warnEvent(warningType, subjectKey, severity, message, now, details) {
  const day = isoDay(now);
  return {
    event_type: 'warning',
    batch_run_id: 'wf-monitor_' + day,
    data: {
      warning_key: warningType + '|' + subjectKey + '|' + day,
      warning_type: warningType,
      severity,
      source_workflow: 'wf-monitor',
      subject_key: subjectKey,
      message,
      details: details || {},
    },
  };
}

function alertToWarningKey(alert, now) {
  const day = isoDay(now);
  switch (alert.type) {
    case 'CONTAINER_DOWN': return 'CONTAINER_DOWN|' + alert.container + '|' + day;
    case 'PG_UNREACHABLE': return 'PG_UNREACHABLE|postgres|' + day;
    case 'WORKFLOW_ERROR': return 'WORKFLOW_ERROR|' + (alert.workflowId || alert.workflowName) + '|' + day;
    case 'SCHEDULE_GAP': return 'SCHEDULE_GAP|' + alert.workflowKey + '|' + day;
    case 'LOW_DISK_SPACE': return 'LOW_DISK_SPACE|C_HOMELAB|' + day;
    case 'BACKUP_STALE': return 'BACKUP_STALE|backup|' + day;
    default: return null;
  }
}

function buildMonitoringReport(input) {
  const now = input.now || new Date().toISOString();
  const alerts = [];
  const warningEvents = [];

  for (const container of (input.containers || [])) {
    if (!container.up) {
      alerts.push({ type: 'CONTAINER_DOWN', container: container.name });
      warningEvents.push(warnEvent('CONTAINER_DOWN', container.name, 'critical', 'Container ' + container.name + ' is down', now, { container: container.name }));
    }
  }

  if (input.postgresReachable === false) {
    alerts.push({ type: 'PG_UNREACHABLE' });
    warningEvents.push(warnEvent('PG_UNREACHABLE', 'postgres', 'critical', 'PostgreSQL is unreachable', now));
  }

  for (const err of (input.workflowErrors || [])) {
    alerts.push({ type: 'WORKFLOW_ERROR', workflowName: err.workflowName, workflowId: err.workflowId, errorAt: err.errorAt });
    warningEvents.push(warnEvent('WORKFLOW_ERROR', err.workflowId || err.workflowName, 'warning', 'Workflow error in ' + err.workflowName + ' at ' + err.errorAt, now, { workflowName: err.workflowName, errorAt: err.errorAt }));
  }

  for (const [key, lastSuccess] of Object.entries(input.scheduleLastSuccess || {})) {
    const ageH = hoursBetween(lastSuccess, now);
    if (ageH > SCHEDULE_GAP_THRESHOLD_H) {
      alerts.push({ type: 'SCHEDULE_GAP', workflowKey: key, ageH, lastSuccessAt: lastSuccess });
      warningEvents.push(warnEvent('SCHEDULE_GAP', key, 'warning', 'Schedule gap: ' + key + ' last success ' + Math.round(ageH) + 'h ago (limit: ' + SCHEDULE_GAP_THRESHOLD_H + 'h)', now, { workflowKey: key, ageH, lastSuccessAt: lastSuccess || null }));
    }
  }

  if (input.diskFreeGb != null && input.diskFreeGb < DISK_THRESHOLD_GB) {
    alerts.push({ type: 'LOW_DISK_SPACE', freeGb: input.diskFreeGb, thresholdGb: DISK_THRESHOLD_GB });
    warningEvents.push(warnEvent('LOW_DISK_SPACE', 'C_HOMELAB', 'warning', 'Disk free ' + input.diskFreeGb + ' GB below threshold ' + DISK_THRESHOLD_GB + ' GB', now, { freeGb: input.diskFreeGb, thresholdGb: DISK_THRESHOLD_GB }));
  }

  const backupAgeH = hoursBetween(input.lastBackupOkAt, now);
  if (backupAgeH > BACKUP_STALE_THRESHOLD_H) {
    alerts.push({ type: 'BACKUP_STALE', ageH: backupAgeH, lastBackupOkAt: input.lastBackupOkAt || null });
    warningEvents.push(warnEvent('BACKUP_STALE', 'backup', 'warning', 'Backup stale: last BACKUP_OK ' + Math.round(backupAgeH) + 'h ago (limit: ' + BACKUP_STALE_THRESHOLD_H + 'h)', now, { ageH: backupAgeH, lastBackupOkAt: input.lastBackupOkAt || null }));
  }

  const existingKeys = new Set(input.existingWarningKeys || []);
  const newAlerts = alerts.filter(a => { const k = alertToWarningKey(a, now); return k === null || !existingKeys.has(k); });
  const mail = buildMail(newAlerts, now);
  return { status: alerts.length > 0 ? 'alert' : 'ok', alerts, warningEvents, mail, shouldSendMail: newAlerts.length > 0 };
}

function buildMail(alerts, now) {
  const day = isoDay(now);
  if (alerts.length === 0) {
    return { sendTo: 'PatrickZinke@gmx.net', subject: 'WF-Monitor ' + day + ': ok', text: 'WF-Monitor ' + day + ': alle Checks ok', html: '<pre>WF-Monitor ' + day + ': alle Checks ok</pre>' };
  }
  const first = alerts.find(a => ['CONTAINER_DOWN','PG_UNREACHABLE','BACKUP_STALE'].includes(a.type)) || alerts[0];
  const detail = first.type === 'CONTAINER_DOWN' ? first.container : first.type;
  const lines = ['WF-Monitor ' + day + ': ' + alerts.length + ' Alert(s)', ''].concat(alerts.map(a => {
    if (a.type === 'CONTAINER_DOWN') return 'CONTAINER_DOWN: ' + a.container + ' ist down';
    if (a.type === 'PG_UNREACHABLE') return 'PG_UNREACHABLE: PostgreSQL nicht erreichbar';
    if (a.type === 'WORKFLOW_ERROR') return 'WORKFLOW_ERROR: ' + a.workflowName + ' Fehler um ' + a.errorAt;
    if (a.type === 'SCHEDULE_GAP') return 'SCHEDULE_GAP: ' + a.workflowKey + ' zuletzt vor ' + Math.round(a.ageH) + 'h (Limit: ' + SCHEDULE_GAP_THRESHOLD_H + 'h)';
    if (a.type === 'LOW_DISK_SPACE') return 'LOW_DISK_SPACE: ' + a.freeGb + ' GB frei (Limit: ' + DISK_THRESHOLD_GB + ' GB)';
    if (a.type === 'BACKUP_STALE') return 'BACKUP_STALE: letztes BACKUP_OK vor ' + Math.round(a.ageH) + 'h (Limit: ' + BACKUP_STALE_THRESHOLD_H + 'h)';
    return a.type;
  }));
  const text = lines.join('\n');
  return { sendTo: 'PatrickZinke@gmx.net', subject: 'WF-Monitor ' + day + ': ALERT - ' + detail, text, html: '<pre>' + text + '</pre>' };
}

// --- Collect data ---

function isHttpUp(nodeName) {
  try {
    const items = $(nodeName).all();
    if (!items || items.length === 0) return false;
    const j = items[0].json;
    if (j.error !== undefined || (j.code && j.code.includes('ECONN'))) return false;
    return true;
  } catch(e) { return false; }
}
const containers = [
  { name: 'homelab-ollama',      up: isHttpUp('HTTP Request - Check homelab-ollama') },
  { name: 'homelab-open-webui',  up: isHttpUp('HTTP Request - Check homelab-open-webui') },
  { name: 'homelab-dashboard',   up: isHttpUp('HTTP Request - Check homelab-dashboard') },
];

const pgRows = $('Postgres - Heartbeat').all();
const postgresReachable = pgRows.length > 0 && pgRows[0].json.heartbeat === 1;
if (!postgresReachable) {
  containers.push({ name: 'homelab-postgres', up: false });
}

const execRows = $('Postgres - n8n Execution Check').all();
const execData = execRows.length > 0 ? execRows[0].json : {};
const rawErrors = execData.recent_errors;
const workflowErrors = (Array.isArray(rawErrors) ? rawErrors : (typeof rawErrors === 'string' ? JSON.parse(rawErrors) : []))
  .map(e => ({ workflowId: e.workflowId, workflowName: e.workflowName || e.workflowId, errorAt: e.errorAt }));
const scheduleLastSuccess = {
  wf5: execData.wf5_last_success || null,
  wf8: execData.wf8_last_success || null,
};

const backupRows = $('Postgres - Last Backup OK At').all();
const lastBackupOkAt = backupRows.length > 0 ? backupRows[0].json.last_backup_ok_at : null;

const warnRows = $('Postgres - Existing Today Warnings').all();
const existingWarningKeys = warnRows.map(r => r.json.warning_key).filter(Boolean);

const report = buildMonitoringReport({
  now: new Date().toISOString(),
  containers,
  postgresReachable,
  workflowErrors,
  scheduleLastSuccess,
  diskFreeGb: null,
  lastBackupOkAt,
  existingWarningKeys,
});

return [{ json: report }];

const report = $('Code - Build Monitoring Report').first().json;
const events = report.warningEvents || [];
if (events.length === 0) return [];
return events.map(e => ({ json: e }));

